def categorize_hall_of_fame_era(start_year):
    if start_year <= 1946:
        return "Pre-Integration Era (1871–1946)"
    elif 1947 <= start_year <= 1972:
        return "Golden Era (1947–1972)"
    elif start_year >= 1973:
        return "Expansion Era (1973+)"
    else:
        return "Unknown Era"

# Example usage:
print(categorize_hall_of_fame_era(1950))  # Output: Golden Era (1947–1972)
print(categorize_hall_of_fame_era(1980))  # Output: Expansion Era (1973+)
